// The Kafka trigger delivers the raw message string in .message
const raw = $input.first().json;
let data;
try {
  data = typeof raw.message === 'string' ? JSON.parse(raw.message) : raw;
} catch (_) {
  data = raw;
}

// Use embed_text from watcher if present; build one otherwise
let embed_text = data.embed_text;
if (!embed_text) {
  const scope = data.namespace ? `in namespace ${data.namespace}` : 'cluster-scoped';
  const labels = Object.entries(data.labels || {}).slice(0,5).map(([k,v])=>`${k}=${v}`).join(', ') || 'none';
  embed_text = `Kubernetes ${data.kind} named ${data.name} ${scope}. Labels: ${labels}. Spec: ${(data.raw_spec_json||'{}').substring(0,600)}`;
}

return [{ json: { ...data, embed_text } }];

const src = $('Parse Message').first().json;

// Build a compact spec summary instead of sending the entire raw_spec_json
// This reduces per-result payload from ~5KB to ~200 bytes
function buildSpecSummary(kind, rawSpec) {
  try {
    const spec = typeof rawSpec === 'string' ? JSON.parse(rawSpec) : (rawSpec || {});
    const parts = [];
    // Deployment/ReplicaSet/StatefulSet/DaemonSet
    if (spec.replicas !== undefined) parts.push(`replicas=${spec.replicas}`);
    // Pod containers
    const containers = spec.containers || spec.template?.spec?.containers || [];
    if (containers.length) {
      parts.push(`containers=[${containers.map(c => `${c.name}:${c.image||'?'}`).join(', ')}]`);
    }
    // Service
    if (spec.type && kind === 'Service') parts.push(`type=${spec.type}`);
    if (spec.ports) parts.push(`ports=[${spec.ports.map(p => `${p.port}/${p.protocol||'TCP'}`).join(',')}]`);
    if (spec.clusterIP) parts.push(`clusterIP=${spec.clusterIP}`);
    // Secret
    if (kind === 'Secret') {
      parts.push(`type=${spec.type || 'Opaque'}`);
      if (spec.dataKeys) parts.push(`keys=[${spec.dataKeys.join(',')}]`);
    }
    // PVC
    if (spec.resources?.requests?.storage) parts.push(`storage=${spec.resources.requests.storage}`);
    if (spec.storageClassName) parts.push(`storageClass=${spec.storageClassName}`);
    // Status info
    if (spec.phase) parts.push(`phase=${spec.phase}`);
    if (spec.readyReplicas !== undefined) parts.push(`ready=${spec.readyReplicas}`);
    if (spec.availableReplicas !== undefined) parts.push(`available=${spec.availableReplicas}`);
    return parts.join('; ') || 'no-spec';
  } catch (_) { return 'parse-error'; }
}

const specSummary = buildSpecSummary(src.kind, src.raw_spec_json);

return [{
  json: {
    pageContent: src.embed_text,
    metadata: {
      resource_uid:           src.resource_uid,
      kind:                   src.kind,
      api_version:            src.api_version,
      namespace:              src.namespace,
      name:                   src.name,
      labels:                 JSON.stringify(src.labels || {}),
      annotations:            JSON.stringify(src.annotations || {}),
      spec_summary:           specSummary,
      last_updated_timestamp: src.last_updated_timestamp
    }
  }
}];
